function IdeaSpark() {
  const prompts = {
    business:['A subscription box for…','An app that connects…','A marketplace for…','A service that automates…','A tool that simplifies…'],
    creative:['A painting of…','A song about…','A story where…','A photo series capturing…','A sculpture representing…'],
    tech:['A wearable that…','An AI that…','A drone for…','A robot that…','A VR experience of…'],
    life:['A workout routine for…','A meal plan featuring…','A travel itinerary to…','A morning ritual with…','A hobby involving…']
  };
  const [category, setCategory] = React.useState('business');
  const [idea, setIdea] = React.useState('');
  const [saved, setSaved] = React.useState([]);

  const generate = ()=>{
    const list = prompts[category];
    setIdea(list[Math.floor(Math.random()*list.length)]);
  };

  React.useEffect(()=>generate(),[category]);

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>Idea Spark</div>
      <div style={{display:'flex',gap:6,marginBottom:12}}>
        {Object.keys(prompts).map(c=> (
          <button key={c} onClick={()=>setCategory(c)}
            style={{padding:'6px 12px',borderRadius:8,border:'1px solid #ccc',background:category===c?'#007AFF':'#fff',color:category===c?'#fff':'#000',cursor:'pointer',fontSize:12,textTransform:'capitalize'}}>
            {c}
          </button>
        ))}
      </div>
      <div style={{padding:16,background:'#f5f5f5',borderRadius:12,marginBottom:12,textAlign:'center'}}>
        <div style={{fontSize:20,fontWeight:600,marginBottom:12}}>{idea}</div>
        <button onClick={generate}
          style={{padding:'8px 16px',borderRadius:8,background:'#FF9500',color:'#fff',border:'none',cursor:'pointer'}}>
          Spark Another
        </button>
      </div>
      <div style={{display:'flex',gap:8,marginBottom:8}}>
        <input id="ideaInput" style={{flex:1,padding:'6px 10px',borderRadius:6,border:'1px solid #ccc',fontSize:13}} placeholder="Add your own idea…"/>
        <button onClick={()=>{
          const el=document.getElementById('ideaInput');
          if(el&&el.value.trim()){setSaved([...saved,el.value.trim()]);el.value='';}
        }} style={{padding:'6px 12px',borderRadius:6,background:'#34C759',color:'#fff',border:'none',cursor:'pointer',fontSize:13}}>
          Save
        </button>
      </div>
      <div style={{flex:1,overflow:'auto'}}>
        {saved.map((s,i)=> (
          <div key={i} style={{display:'flex',justifyContent:'space-between',padding:'6px 0',borderBottom:'1px solid #eee'}}>
            <span style={{fontSize:13}}>{s}</span>
            <button onClick={()=>setSaved(saved.filter((_,j)=>j!==i))}
              style={{background:'none',border:'none',color:'#FF3B30',cursor:'pointer',fontSize:12}}>×</button>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<IdeaSpark/>);
